#include <vector>
#include <iostream>
#include <immintrin.h>

#pragma GCC target("avx2")

using namespace std;

struct DNA_Sample
{
    string name;
    int length;
    char *bp1;
    char *bp2;
};

vector<DNA_Sample> catalog;

bool checkCorrectBasePair(char b1, char b2)
{

    char lcb1 = 'x';
    char lcb2 = 'x';

    if (b1 == 'a' || b1 == 'A')
        lcb1 = 'A';
    if (b1 == 't' || b1 == 'T')
        lcb1 = 'T';
    if (b1 == 'g' || b1 == 'G')
        lcb1 = 'G';
    if (b1 == 'c' || b1 == 'C')
        lcb1 = 'C';

    if (b2 == 'a' || b2 == 'A')
        lcb2 = 'A';
    if (b2 == 't' || b2 == 'T')
        lcb2 = 'T';
    if (b2 == 'g' || b2 == 'G')
        lcb2 = 'G';
    if (b2 == 'c' || b2 == 'C')
        lcb2 = 'C';

    if (b1 == ' ' || b1 == ' ' || b1 == '\0' || b2 == '\0')
    {
        return true; // ignore padding
    }

    if (lcb1 == 'x' || lcb2 == 'x')
    {
        cout << " invalid base " << b1 << " - " << b2 << endl;
        return false;
    }

    string basePair = "";

    basePair.push_back(lcb1);
    basePair.push_back(lcb2);

    if (basePair != "AT" && basePair != "TA" && basePair != "GC" && basePair != "CG")
    {
        cout << "invalid base pair " << basePair << endl;
        return false;
    }

    return true;
}

float matchCheckHighAcc(DNA_Sample sample, int padding, int catalogIdx)
{

    int j = catalogIdx;

    int matches = 0;
    for (int i = padding; i < sample.length; i++)
    {
        if (sample.bp1[i] - catalog[j].bp1[i] == 0 && sample.bp2[i] - catalog[j].bp2[i] == 0)
        {
            if (checkCorrectBasePair(sample.bp1[i], sample.bp2[i]))
                matches++;
        }
    }

    return (float)matches / (float)(sample.length - padding);
}

vector<float> matchCheckLowAcc(DNA_Sample sample, int padding)
{
    __m256i simdA;
    __m256i simdB;
    __m256i simdRes;

    vector<float> results(catalog.size(), 0.0f);

    for (int j = 0; j < catalog.size(); j++)
    {
        int matches = 0;
        int i = 0;
        for (; i < sample.length - 32; i += 32)
        {
            simdA = _mm256_set_epi8(sample.bp1[i], sample.bp1[i + 1], sample.bp1[i + 2], sample.bp1[i + 3], sample.bp1[i + 4], sample.bp1[i + 5], sample.bp1[i + 6], sample.bp1[i + 7], sample.bp1[i + 8], sample.bp1[i + 9], sample.bp1[i + 10], sample.bp1[i + 11], sample.bp1[i + 12], sample.bp1[i + 13], sample.bp1[i + 14], sample.bp1[i + 15], sample.bp1[i + 16], sample.bp1[i + 17], sample.bp1[i + 18], sample.bp1[i + 19], sample.bp1[i + 20], sample.bp1[i + 21], sample.bp1[i + 22], sample.bp1[i + 23], sample.bp1[i + 24], sample.bp1[i + 25], sample.bp1[i + 26], sample.bp1[i + 27], sample.bp1[i + 28], sample.bp1[i + 29], sample.bp1[i + 30], sample.bp1[i + 31]);
            simdB = _mm256_set_epi8(catalog[j].bp1[i], catalog[j].bp1[i + 1], catalog[j].bp1[i + 2], catalog[j].bp1[i + 3], catalog[j].bp1[i + 4], catalog[j].bp1[i + 5], catalog[j].bp1[i + 6], catalog[j].bp1[i + 7], catalog[j].bp1[i + 8], catalog[j].bp1[i + 9], catalog[j].bp1[i + 10], catalog[j].bp1[i + 11], catalog[j].bp1[i + 12], catalog[j].bp1[i + 13], catalog[j].bp1[i + 14], catalog[j].bp1[i + 15], catalog[j].bp1[i + 16], catalog[j].bp1[i + 17], catalog[j].bp1[i + 18], catalog[j].bp1[i + 19], catalog[j].bp1[i + 20], catalog[j].bp1[i + 21], catalog[j].bp1[i + 22], catalog[j].bp1[i + 23], catalog[j].bp1[i + 24], catalog[j].bp1[i + 25], catalog[j].bp1[i + 26], catalog[j].bp1[i + 27], catalog[j].bp1[i + 28], catalog[j].bp1[i + 29], catalog[j].bp1[i + 30], catalog[j].bp1[i + 31]);
            simdRes = _mm256_cmpeq_epi8(simdA, simdB);

            if (_mm256_movemask_epi8(simdRes) != 0xff)
            {
                matches += 32;
            }
        }

        for (; i < sample.length; i++)
        {
            if (sample.bp1[i] - catalog[j].bp1[i] == 0 && sample.bp2[i] - catalog[j].bp2[i] == 0)
            {
                matches++;
            }
        }

        results[j] = (float)matches / (float)(sample.length - padding);
    }

    return results;
}

void populateCatalog()
{

    int len = 100;

    DNA_Sample sample1 = {
        "species 1",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample2 = {
        "species 2",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample3 = {
        "species 3",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample4 = {
        "species 4",
        10000,
        (char *)"",
        (char *)"",
    };
    DNA_Sample sample5 = {
        "species 5",
        10000,
        (char *)"",
        (char *)"",
    };
    catalog.push_back(sample1);
    catalog.push_back(sample2);
    catalog.push_back(sample3);
    catalog.push_back(sample4);
    catalog.push_back(sample5);

    // randomly generated samples
    int rgen = 200;
    srand(time(NULL));

    for (int i = 0; i < rgen; i++)
    {
        string base1 = "";
        string base2 = "";

        for (int i = 0; i < 9999; i++)
        {
            int rand_num = (int)(rand() % 4);

            if (rand_num == 0)
            {
                base1 += 'A';
                base2 += 'T';
            }
            else if (rand_num == 1)
            {
                base1 += 'T';
                base2 += 'A';
            }
            else if (rand_num == 2)
            {
                base1 += 'G';
                base2 += 'C';
            }
            else
            {

                base1 += 'C';
                base2 += 'G';
            }
        }

        DNA_Sample sampleN = {
            "random spc " + to_string(i),
            10000,
            (char *)base1.c_str(),
            (char *)base2.c_str(),
        };

        catalog.push_back(sampleN);
    }
}

int main()
{

    // initilizing sample data
    cout << "initlizing demo data \n";
    populateCatalog();
    DNA_Sample sampleToTest = {
        "test sample",
        9608,
        (char *)"",
        (char *)"",
    };

    const int catalogSampleLengths = 10000;

    string paddStart = "";
    string paddEnd = "";
    string paddStartHighAcc = "";
    string paddEndHighAcc = "";

    for (int i = 0; i < catalogSampleLengths - sampleToTest.length; i++)
    {
        paddStart += " ";
        paddStartHighAcc += " ";
    }

    cout << "starting calculations... \n";
    // performing computation low acc
    clock_t simd_start = clock();
    vector<float> resultsBest(catalog.size(), 0.0f);

    for (int i = 0; i < catalogSampleLengths - sampleToTest.length; i++)
    {
        // pads

        string paddedBp1 = (paddStart + sampleToTest.bp1 + paddEnd);
        string paddedBp2 = (paddStart + sampleToTest.bp2 + paddEnd);

        DNA_Sample sampleToTestPadded = {
            "test sample padded",
            (int)paddStart.length() + sampleToTest.length,
            (char *)paddedBp1.c_str(),
            (char *)paddedBp2.c_str(),
        };

        vector<float> res = matchCheckLowAcc(sampleToTestPadded, paddStart.length());

        for (int j = 0; j < res.size(); j++)
        {
            if (res[j] > resultsBest[j])
            {
                resultsBest[j] = res[j];
            }
        }

        paddStart.pop_back();
        paddEnd.push_back(' ');
    }

    int bestmatch = 0;
    for (int j = 0; j < resultsBest.size(); j++)
    {
        if (resultsBest[j] > resultsBest[bestmatch])
            bestmatch = j;
    }

    // high accuracy
    float bestmatchHighAcc = 0;
    for (int i = 0; i < catalogSampleLengths - sampleToTest.length; i++)
    {
        string paddedBp1 = (paddStartHighAcc + sampleToTest.bp1 + paddEndHighAcc);
        string paddedBp2 = (paddStartHighAcc + sampleToTest.bp2 + paddEndHighAcc);

        DNA_Sample sampleToTestPadded = {
            "test sample padded",
            (int)paddStartHighAcc.length() + sampleToTest.length,
            (char *)paddedBp1.c_str(),
            (char *)paddedBp2.c_str(),
        };

        float res = matchCheckHighAcc(sampleToTestPadded, paddStartHighAcc.length(), bestmatch);

        if (res > bestmatchHighAcc)
        {
            bestmatchHighAcc = res;
        }

        paddStartHighAcc.pop_back();
        paddEndHighAcc.push_back(' ');
    }

    clock_t simd_end = clock();
    double simd_time = 0.0;
    simd_time = simd_time + (double)(simd_end - simd_start);
    simd_time = simd_time / CLOCKS_PER_SEC;

    cout << "\n\nBest match: " << catalog[bestmatch].name << " : " << bestmatchHighAcc * 100 << "% match\n";

    cout << "\n\ncalculations finished in " << simd_time << " sec" << '\n';
}
